import okhttp3.*;
import java.io.*;
public class Test {
public static void main(String[] args) {
OkHttpClient client = new OkHttpClient();
Request request = new Request.Builder().url("https://api.kroger.com/catalog/v2/products?filter.locations.id.eq=MKTPLACE&filter.locations.fulfillment.eq=SHIP").get()
.addHeader("Content-Type", "application/x-www-form-urlencoded")
.addHeader("Authorization","Bearer {{TOKEN}}")
.build();
try {
ResponseBody responseBody = client.newCall(request).execute().body();
System.out.println(responseBody.string());
} catch (IOException e) {
System.out.println(e.getMessage());
}
}
}

const axios = require('axios');
let config = {
  headers: {
    "Content-Type": "application/x-www-form-urlencoded",
    "Authorization": "Bearer {{TOKEN}}"
  },
}
axios.get('https://api.kroger.com/catalog/v2/products?filter.locations.id.eq=MKTPLACE&filter.locations.fulfillment.eq=SHIP',config)
.then(response => {
    console.log(response.data);
})
.catch(error => {
    console.log(error);
});

